var gcdOfOddEvenSums = function(n) {
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    const sumOdd = n * n;
    const sumEven = n * (n + 1);
    return gcd(sumOdd, sumEven);
};
